solutions.cpp:
class Solution {
public:
    std::string concatenate(const std::string& a, const std::string& b) {
        return a.substr(0, a.find_last_not_of(" ") + 1) + b.substr(0, b.find_last_not_of(" ") + 1);
    }
};

// Driver code to test above function
int main() {
    Solution s;
    std::string a, b;
    std::getline(std::cin, a);
    std::getline(std::cin, b);
    std::cout << s.concatenate(a, b) << std::endl;
    return 0;
}
